$script=@'
const TOKEN=process.env.GHL_PRIVATE_INTEGRATION_TOKEN||process.env.GHL_PRIVATE_INTEGRATION_TOKEN_TJB||process.env.GHL_TOKEN;
const LOC='TW8JsPW5NMnA3tfK2XLn';
const BASE='https://services.leadconnectorhq.com';
const headers={Authorization:`Bearer ${TOKEN}`,Version:'2021-07-28',Accept:'application/json','Content-Type':'application/json'};
if(!TOKEN){console.error('Missing GHL token');process.exit(2)}
const sinceMs=Date.now()-6*60*60*1000;
const sleep=ms=>new Promise(r=>setTimeout(r,ms)); let last=0;
async function api(method,ep,body){const n=Date.now(); if(n-last<350) await sleep(350-(n-last)); last=Date.now(); const r=await fetch(BASE+ep,{method,headers,body:body?JSON.stringify(body):undefined}); const tx=await r.text(); let j; try{j=JSON.parse(tx)}catch{j={raw:tx}}; if(!r.ok) throw new Error(`${method} ${ep} => ${r.status} ${tx.slice(0,220)}`); return j;}
function getCFVal(contact,idMap,key){const id=idMap[key];const arr=Array.isArray(contact.customFields)?contact.customFields:[]; if(id){const f=arr.find(x=>x.id===id); if(f) return f.value;} const byKey=arr.find(x=>String(x.fieldKey||x.key||x.name||'').toLowerCase().includes(key)); return byKey?.value;}
function num(v){const n=Number(v); return Number.isFinite(n)?n:0;}
function ts(v){const d=(typeof v==='number')?new Date(v):new Date(v||0); const t=d.getTime(); return Number.isFinite(t)?t:0;}

async function allContacts(){
  let ep=`/contacts/?locationId=${LOC}&limit=100`;
  const out=[];
  while(ep){
    const j=await api('GET',ep);
    out.push(...(j.contacts||[]));
    const np=j.meta?.nextPageUrl;
    if(np){ ep=np.replace(BASE,''); } else ep=null;
  }
  return out;
}

async function main(){
  const cfs=await api('GET',`/locations/${LOC}/customFields`);
  const allCF=Array.isArray(cfs.customFields)?cfs.customFields:[];
  const idMap={};
  for(const f of allCF){
    const blob=`${f.name||''} ${f.fieldKey||''}`.toLowerCase();
    if(blob.includes('lead_score')||blob.includes('lead score')) idMap.lead_score=f.id;
    if(blob.includes('alignment_score')||blob.includes('alignment score')) idMap.alignment_score=f.id;
    if(blob.includes('email_opens')||blob.includes('email opens')) idMap.email_opens=f.id;
  }

  const contacts=await allContacts();
  const modified=contacts.filter(c=>ts(c.dateUpdated||c.dateAdded)>=sinceMs);

  const hot=[]; let updated=0; const failures=[];
  for(const c of modified){
    const contactId=c.id;
    const full=(await api('GET',`/contacts/${contactId}`)).contact || c;
    const convs=(await api('GET',`/conversations/search?locationId=${LOC}&contactId=${contactId}`)).conversations||[];

    // response speed + SMS replies from conversation messages
    let bestLagH=Infinity; let smsReplies=0;
    for(const conv of convs){
      const msgs=((await api('GET',`/conversations/${conv.id}/messages?limit=100`)).messages||{}).messages||[];
      const sorted=[...msgs].sort((a,b)=>ts(a.dateAdded)-ts(b.dateAdded));
      for(let i=0;i<sorted.length;i++){
        const m=sorted[i];
        const dir=String(m.direction||'').toLowerCase();
        const typeStr=String(m.messageType||m.type||'').toLowerCase();
        const isSms = typeStr.includes('sms') || typeStr==='0' || typeStr==='1' || typeStr==='14';
        if(dir==='inbound' && isSms) smsReplies++;
        if(dir==='inbound'){
          for(let j=i+1;j<sorted.length;j++){
            if(String(sorted[j].direction||'').toLowerCase()==='outbound'){
              const lag=(ts(sorted[j].dateAdded)-ts(m.dateAdded))/36e5;
              if(lag>=0 && lag<bestLagH) bestLagH=lag;
              break;
            }
          }
        }
      }
    }

    let score=0;
    if(Number.isFinite(bestLagH)){
      if(bestLagH<1) score+=20; else if(bestLagH<24) score+=15;
    }
    if(full.emailVerified) score+=10;
    score += Math.min(num(getCFVal(full,idMap,'email_opens'))*2,10);
    score += Math.min(smsReplies*5,20);
    score += Math.round((num(getCFVal(full,idMap,'alignment_score'))/100)*20);
    const tags=Array.isArray(full.tags)?full.tags:[];
    if(tags.includes('scorecard-lead')) score+=10;
    if(tags.includes('ebook-buyer')) score+=10;
    score=Math.max(0,Math.min(100,score));

    try{
      if(idMap.lead_score){
        await api('PUT',`/contacts/${contactId}`,{customFields:[{id:idMap.lead_score,value:score}]});
      } else {
        await api('PUT',`/contacts/${contactId}`,{customFields:[{key:'lead_score',field_value:String(score)}]});
      }
      updated++;
    } catch(e){ failures.push({contactId,error:e.message}); }

    if(score>=90){
      hot.push({contactId,name:[full.firstName,full.lastName].filter(Boolean).join(' ').trim()||full.contactName||'Unknown',score});
    }
  }

  console.log(JSON.stringify({modifiedCount:modified.length,updated,hot,failures,fieldIds:idMap},null,2));
}
main().catch(e=>{console.error(e.message);process.exit(1)});
'@; node -e $script

